(window.webpackJsonp=window.webpackJsonp||[]).push([[22],{386:function(n,t,e){"use strict";e.r(t);var s=e(42),a=Object(s.a)({},(function(){var n=this,t=n.$createElement,e=n._self._c||t;return e("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[e("p",[n._v("简单回顾一下2020\nsoul mate\nwork\nSpark 有哪些是虚假的 哪些是因为虚荣因为被夸赞")]),n._v(" "),e("p",[n._v("一天的规划\n上班摸鱼玩手机：一些想法写在备忘录上 寻寻觅觅我的spark\n上班摸鱼学习时间：想法和知识点写在vscode上，推到git page\n长期的规划\n关于下班后的时间\n写写好玩的程序+看电视剧\n唱歌\n周末的时间\n弹吉他\n学习理财")]),n._v(" "),e("h1",{attrs:{id:"随笔"}},[e("a",{staticClass:"header-anchor",attrs:{href:"#随笔"}},[n._v("#")]),n._v(" 随笔")]),n._v(" "),e("p",[n._v("想提笔许久了，却一直耽于繁忙的工作，沉迷于逝去的难过中，没能好好关照自己的过去、当下与未来。\n一不留神，2020就这么过去了。因为疫情，这一年很魔幻，许多未曾设想的情节，发生了，在史书中留下深刻的一笔。而作为历史长河中、\n芸芸众生里一个小小的我，也有着惊奇的际遇，误打误撞来到北京，遇到了好些惊艳的人，闯进了现在的工作和生活里。")]),n._v(" "),e("p",[n._v("犹记得一月份初，我在为大学里最艰难的一个考试周奋斗。失恋了小半年，竟一直没好，这份痛苦与学业压力相生相伴，极其煎熬。比方说，我会在咖啡馆里，一遍遍听着与爱情有关的歌曲，小心翼翼掉眼泪；比方说我会在一场考试结束后，跑到秘密基地小天台上抑郁地唱着歌，因为快要抗不下去了。")]),n._v(" "),e("p",[n._v("一月中下旬，一路向南的动车，带我回到了熟悉的滨海小镇。而后迅速地，疫情爆发，一开始忧心忡忡，百般关注；到后来日渐习惯，百无聊赖。\n就着找暑期实习的规划，开始了解各种岗位。「前端」进入了我的视野。与我的设计、排版和编程经历吻合，“就是你了”。从一无所知，到知道「js、css、html、框架」四大基础，到了解「开源项目、博客、实习经历」三大敲门砖。随后我开始准备面试。")]),n._v(" "),e("p",[n._v("也许起步晚了，但很努力，运气也极好。学了两个月，面试失败数次后，三月下旬，我拿到了 offer。有些浪漫地想，也许冥冥中自有天意。而面试官的知遇之恩，我必将永远感念。")]),n._v(" "),e("p",[n._v("五月四日，飞行了三千公里后，我来到了北京。一个遥远得不会出现在梦里的城市，却突然成了现实。\n然后我遇到了我超级无敌巨喜欢的人。可正是那句，I met my soulmate, but he didn't. 遇见已经是一种幸运了，唯有感恩。而我要同他一样，做一个与光同尘暗自发光的人。")]),n._v(" "),e("p",[n._v("然后我遇到了很喜欢我的人。哦那就好多了。可再真诚的喜欢，也没能打动我，这坚定了我只要双向奔赴的恋爱的决心。永远都是，「不想恋爱，只是遇到了想爱的人」。\n然后我遇到了很多温暖的人。有些人遇到了，就会是一辈子的朋友了。虽然只有亿万分之一的概率，我们相遇，但，我们相遇了！比如芬芬姐。我们一起骑车漫游在清华校道上；我们一起整理小院的杂物，在小院里种花、看星星、和隔壁老师聚餐；我们一起做饭，本大厨对火候和调味还是很有feel的；我们一起玩分手厨房；我们一起看京城大雪纷飞，看薄雪覆盖的故宫...比如述述，一个初见平平无奇，后来才知道极尽细心体贴的女孩。")]),n._v(" "),e("p",[n._v("然后我有了稳定的工作。一开始入职时懵懵懂懂，只有学了两三个月的三脚猫功夫，做事自然战战兢兢，生怕触及知识盲区。还好我有一个特别好的导师，他总是能从无到有地，把一个陌生的事物给我讲得清清楚楚。他好像很严肃，却不带一丝感情地温柔着，再接触多点，他的幽默风趣便展露无遗了。在陌生又快乐的氛围里，我快速成长着。\n边实习边上课肝作业，边实习边准备转正答辩，我的日子被填得满满的。忙完了学业和转正，我才渐渐拥有属于自己的时间。到后来，我又被毕设压着，总忙忙碌碌。但我会更关注学习成长和work life balance了。比起上学时，被超满课表或考试周支配，我想现在的我拥有更多成长和生活的自由。")]),n._v(" "),e("p",[n._v("然后我依旧在寻找自己的 spark。看《心灵奇旅》的时候，我产生了深深的共鸣。某一刻我觉得，编剧就站在我眼前，把他的想法向绣球一样抛出，而我妥妥地接到了，那种共鸣感无可比拟。主角twenty-two 一直在寻觅自己的 spark，却始终找不到。我好像看到了那个，对什么都感兴趣，却又谈不上狂热的自己。在看到别人对一些事物表现出尖叫、疯狂的模样时，我觉得自己似乎缺了些什么。从前我也狂热地追求过什么，比如成绩、技能、才艺，可那是任务驱动、是“生活所迫”、是盲目从众，看似大步向前，实则不知何去何从；有时还会因为虚荣心而附庸风雅，去假装喜欢一些美好的事物，愈发迷失了自己。")]),n._v(" "),e("p",[n._v("直到电影告诉我，原来叶子和天空，也可以是 spark。我与太阳挥手，同海鸥问候，爱天爱地地四处风流。让我真正心动的事物，藏在生活的角落里，原来无时无刻不陪伴着我，比方说快门和故事、音乐和文字、星空和阳光。多读懂这个世界，多体验前人今人创造的美好，已然足够。\n我的喜好太别致了，以至于我自己都捉摸不透。\n不过寻找 spark 依旧是终身事业，要慢慢地，探寻自己的喜好与天赋，让生活被喜爱的事物包围。\n本想写 2021 的期望，却好像，答案已经在 2020 里了。就从容低调地成长吧。")])])}),[],!1,null,null,null);t.default=a.exports}}]);